mapper.select:
SELECT d.doc_id, d.doc_title, d.form_code, d.drafter_no, d.drafter_name,
       d.drafter_dept, d.status, d.created_at, d.updated_at
FROM platform_v3.ap_document d
WHERE 1=1


        AND d.status = 'DRAFT' AND d.drafter_no = #{userNo}


        AND d.drafter_no = #{userNo}


        AND d.status = 'PENDING'
        AND EXISTS (
            SELECT 1 FROM platform_v3.ap_approval_line l
            WHERE l.doc_id = d.doc_id AND l.approver_no = #{userNo}
              AND l.status = 'PENDING'
        )


        AND d.status = 'IN_PROGRESS'
        AND (d.drafter_no = #{userNo} OR EXISTS (
            SELECT 1 FROM platform_v3.ap_approval_line l
            WHERE l.doc_id = d.doc_id AND l.approver_no = #{userNo}
        ))


        AND d.status = 'APPROVED'
        AND (d.drafter_no = #{userNo} OR EXISTS (
            SELECT 1 FROM platform_v3.ap_approval_line l
            WHERE l.doc_id = d.doc_id AND l.approver_no = #{userNo}
        ))


        AND d.status = 'REJECTED'
        AND (d.drafter_no = #{userNo} OR EXISTS (
            SELECT 1 FROM platform_v3.ap_approval_line l
            WHERE l.doc_id = d.doc_id AND l.approver_no = #{userNo}
        ))


        AND EXISTS (
            SELECT 1 FROM platform_v3.ap_approval_line l
            WHERE l.doc_id = d.doc_id AND l.approver_no = #{userNo}
        )


        AND FALSE


        AND d.drafter_dept IS NOT NULL


        AND TRUE



    AND (d.doc_title LIKE '%' || #{keyword} || '%' OR d.drafter_name LIKE '%' || #{keyword} || '%')

ORDER BY d.created_at DESC
LIMIT 200

mapper.update:
UPDATE platform_v3.ap_document
SET status = #{status}, updated_at = NOW()
WHERE doc_id = #{docId}

UPDATE platform_v3.ap_approval_line
SET status = 'PENDING', comment = NULL, acted_at = NULL, acted_by_no = NULL
WHERE doc_id = #{docId}
